111	            Cursor<byte[]> cursor = connection.keyCommands().scan(opts);
112	            try {
113	                while (cursor.hasNext()) {
114	                    result.add(new String(cursor.next(), StandardCharsets.UTF_8));
115	                }
116	            } finally {
117	                try { cursor.close(); } catch (IOException ignored) {}
118	            }
119	            return result;
120	        });
121	    }
