import java.time.Duration;
import java.util.stream.StreamSupport;

import static java.util.stream.Collectors.joining;

@Configuration
@EnableCaching
public class CacheConfig {

    @Bean
    public RedisCacheManager cacheManager(RedisConnectionFactory connectionFactory) {
        RedisCacheConfiguration config = RedisCacheConfiguration.defaultCacheConfig()
                .entryTtl(Duration.ofMinutes(10))
                .disableCachingNullValues()
                .serializeValuesWith(
                    RedisSerializationContext.SerializationPair.fromSerializer(
                        new GenericJackson2JsonRedisSerializer()
                    )
                );

        return RedisCacheManager.builder(connectionFactory)
                .cacheDefaults(config)
                .build();
    }

    // Produces a deterministic key from Pageable so Sort.toString() instability
    // (insertion-order varies across JVM versions) cannot create phantom cache entries.
    @Bean("recommendationKeyGenerator")
    public KeyGenerator recommendationKeyGenerator() {
        return (target, method, params) -> {
            Long userId = (Long) params[0];
            Pageable pageable = (Pageable) params[1];
            String sortKey = StreamSupport
                .stream(pageable.getSort().spliterator(), false)
                .map(o -> o.getProperty() + "_" + o.getDirection())
                .sorted()
                .collect(joining(","));
            return userId + ":" + pageable.getPageNumber() + ":" + pageable.getPageSize() + ":" + sortKey;
        };
    }
}
