public void deleteRecommendation(Long id) {
    Recommendation rec = recommendationRepository.findById(id)
            .orElseThrow(() -> new NotFoundException("Recomendação não encontrada com ID: " + id));
    recommendationRepository.delete(rec);
    evictUserCache(rec.getUserId());
}

private void evictUserCache(Long userId) {
    String prefix = redisCacheManager.getCacheConfigurations()
        .getOrDefault(CACHE_NAME, redisCacheManager.getDefaultCacheConfiguration())
        .getKeyPrefixFor(CACHE_NAME);
    Set<String> keys = scanKeys(prefix + userId + ":*");
    if (!keys.isEmpty()) {
        redisTemplate.delete(keys);
    }
}

private Set<String> scanKeys(String pattern) {
    return redisTemplate.execute((RedisCallback<Set<String>>) connection -> {
        Set<String> result = new HashSet<>();
        ScanOptions opts = ScanOptions.scanOptions().match(pattern).count(200).build();
        Cursor<byte[]> cursor = connection.keyCommands().scan(opts);
        try {
            while (cursor.hasNext()) {
                result.add(new String(cursor.next(), StandardCharsets.UTF_8));
            }
        } finally {
            try { cursor.close(); } catch (IOException ignored) {}
        }
        return result;
    });
}
