import com.example.recommendation.dtos.AssessmentTriggerDTO;
import com.example.recommendation.dtos.RecommendationDTO;
import com.example.recommendation.dtos.ResourceDTO;
import com.example.recommendation.model.Recommendation;
import com.example.recommendation.model.Resource;
import com.example.recommendation.exception.NotFoundException;
import com.example.recommendation.repository.RecommendationRepository;
import com.example.recommendation.repository.ResourceRepository;
import org.springframework.cache.annotation.Cacheable;
import org.springframework.data.domain.Pageable;
import org.springframework.data.redis.cache.RedisCacheManager;
import org.springframework.data.redis.core.Cursor;
import org.springframework.data.redis.core.RedisCallback;
import org.springframework.data.redis.core.ScanOptions;
import org.springframework.data.redis.core.StringRedisTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.transaction.support.TransactionSynchronization;
import org.springframework.transaction.support.TransactionSynchronizationManager;

import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

@Service
public class RecommendationService {

    static final String CACHE_NAME = "recommendations";

    private final RecommendationRepository recommendationRepository;
    private final ResourceRepository resourceRepository;
    private final StringRedisTemplate redisTemplate;
    private final RedisCacheManager redisCacheManager;

    public RecommendationService(RecommendationRepository recommendationRepository,
                                 ResourceRepository resourceRepository,
                                 StringRedisTemplate redisTemplate,
                                 RedisCacheManager redisCacheManager) {
        this.recommendationRepository = recommendationRepository;
        this.resourceRepository = resourceRepository;
        this.redisTemplate = redisTemplate;
        this.redisCacheManager = redisCacheManager;
    }

    @Transactional
    public void generateRecommendation(AssessmentTriggerDTO trigger) {
        List<Resource> resources = resourceRepository.findByCompetencyIdAndLevelOrUnclassified(
                trigger.getCompetencyId(), trigger.getLevel());

        if (resources.isEmpty()) {
            throw new NotFoundException("Nenhum recurso encontrado para a competência ID: "
                + trigger.getCompetencyId() + " e nível: " + trigger.getLevel());
        }

        // Apaga recomendações anteriores do mesmo userId+competency antes de recriar,
        // garantindo idempotência: chamadas repetidas ou concorrentes substituem em vez de acumular duplicatas.
        recommendationRepository.deleteByUserIdAndCompetencyId(
                trigger.getUserId(), trigger.getCompetencyId());

        List<Recommendation> recommendations = resources.stream().map(resource -> {
            Recommendation rec = new Recommendation();
            rec.setUserId(trigger.getUserId());
            rec.setResource(resource);
            rec.setDescription("Recomendado com base na competência ID: "
                + trigger.getCompetencyId());
            return rec;
        }).collect(Collectors.toList());

        recommendationRepository.saveAll(recommendations);

        // Evicção só após o commit — falha no Redis não causa rollback do banco
        // e um retry não recria duplicatas (o delete acima já garante isso).
        Long userId = trigger.getUserId();
        TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
            @Override
            public void afterCommit() {
                evictUserCache(userId);
            }
        });
    }

    @Cacheable(value = CACHE_NAME, keyGenerator = "recommendationKeyGenerator")
    public List<RecommendationDTO> getUserRecommendations(Long userId, Pageable pageable) {
        return recommendationRepository.findByUserId(userId, pageable)
                .stream()
                .map(this::toDTO)
                .collect(Collectors.toList());
    }

    @Transactional
    public void deleteRecommendation(Long id) {
        Recommendation rec = recommendationRepository.findById(id)
                .orElseThrow(() -> new NotFoundException("Recomendação não encontrada com ID: " + id));
        recommendationRepository.delete(rec);

        // Evicção após commit — Redis down não retorna 500 com o banco já modificado.
        Long userId = rec.getUserId();
        TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
            @Override
            public void afterCommit() {
                evictUserCache(userId);
            }
        });
    }

    private void evictUserCache(Long userId) {
        String prefix = redisCacheManager.getCacheConfigurations()
            .getOrDefault(CACHE_NAME, redisCacheManager.getDefaultCacheConfiguration())
            .getKeyPrefixFor(CACHE_NAME);
        Set<String> keys = scanKeys(prefix + userId + ":*");
        if (!keys.isEmpty()) {
            redisTemplate.delete(keys);
        }
    }

    // SCAN é O(1) por chamada e não bloqueia o Redis; KEYS é O(N) e bloqueia.
    private Set<String> scanKeys(String pattern) {
        return redisTemplate.execute((RedisCallback<Set<String>>) connection -> {
            Set<String> result = new HashSet<>();
            ScanOptions opts = ScanOptions.scanOptions().match(pattern).count(200).build();
            Cursor<byte[]> cursor = connection.keyCommands().scan(opts);
            try {
                while (cursor.hasNext()) {
                    result.add(new String(cursor.next(), StandardCharsets.UTF_8));
                }
            } finally {
                try { cursor.close(); } catch (IOException ignored) {}
            }
            return result;
        });
    }

    private RecommendationDTO toDTO(Recommendation rec) {
        RecommendationDTO dto = new RecommendationDTO();
        dto.setId(rec.getId());
        dto.setUserId(rec.getUserId());
        dto.setDescription(rec.getDescription());

        if (rec.getResource() != null) {
            ResourceDTO resourceDTO = new ResourceDTO();
            resourceDTO.setId(rec.getResource().getId());
            resourceDTO.setName(rec.getResource().getName());
            resourceDTO.setDescription(rec.getResource().getDescription());
            resourceDTO.setUrl(rec.getResource().getUrl());
            resourceDTO.setCompetencyId(rec.getResource().getCompetencyId());
            resourceDTO.setLevel(rec.getResource().getLevel());
            dto.setResource(resourceDTO);
        }

        return dto;
    }
}
