499	+import org.springframework.http.HttpStatus;
500	+import org.springframework.http.ResponseEntity;
501	+import org.springframework.web.bind.MethodArgumentNotValidException;
502	+import org.springframework.web.bind.annotation.ExceptionHandler;
503	+import org.springframework.web.bind.annotation.RestControllerAdvice;
504	+
505	+import java.time.Instant;
506	+import java.util.LinkedHashMap;
507	+import java.util.List;
508	+import java.util.Map;
509	+
510	+@RestControllerAdvice
511	+public class GlobalExceptionHandler {
512	+
513	+    @ExceptionHandler(MethodArgumentNotValidException.class)
514	+    public ResponseEntity<Map<String, Object>> handleValidation(MethodArgumentNotValidException ex) {
515	+        List<String> errors = ex.getBindingResult().getFieldErrors().stream()
516	+                .map(f -> f.getField() + ": " + f.getDefaultMessage())
517	+                .toList();
518	+
519	+        return ResponseEntity.badRequest().body(body(HttpStatus.BAD_REQUEST, "Dados inválidos", errors));
520	+    }
521	+
522	+    @ExceptionHandler(RuntimeException.class)
523	+    public ResponseEntity<Map<String, Object>> handleRuntime(RuntimeException ex) {
524	+        return ResponseEntity.status(HttpStatus.NOT_FOUND)
525	+                .body(body(HttpStatus.NOT_FOUND, ex.getMessage(), null));
526	+    }
527	+
528	+    @ExceptionHandler(Exception.class)
529	+    public ResponseEntity<Map<String, Object>> handleGeneric(Exception ex) {
530	+        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
531	+                .body(body(HttpStatus.INTERNAL_SERVER_ERROR, "Erro interno no servidor", null));
532	+    }
533	+
534	+    private Map<String, Object> body(HttpStatus status, String message, List<String> errors) {
535	+        Map<String, Object> body = new LinkedHashMap<>();
536	+        body.put("timestamp", Instant.now());
537	+        body.put("status", status.value());
538	+        body.put("error", status.getReasonPhrase());
539	+        body.put("message", message);
540	+        if (errors != null) body.put("errors", errors);
541	+        return body;
542	+    }
543	+}
